}

extends.example:
class Dog extends Animal {
    void speak() { System.out.println("Woof"); }
}

implements.example:
class Circle implements Shape {
    public double area() { return Math.PI * r * r; }
}

this.example:
class Point {
    int x;
    Point(int x) {
        this.x = x;
    }
}

super.example:
class Dog extends Animal {
    Dog(String name) {
        super(name);
    }
}

case.example:
switch (grade) {
    case 'A' -> System.out.println("Great");
    default -> System.out.println("Keep going");
}

break.example:
for (int i = 0; i < 10; i++) {
    if (i == 3) break;
}

continue.example:
for (int i = 0; i < 5; i++) {
    if (i % 2 == 0) continue;
    System.out.println(i);
}

return.example:
int square(int x) {
    return x * x;
}

try.example:
try {
    int x = 1 / 0;
} catch (ArithmeticException e) {
    System.out.println(e.getMessage());
}

throw.example:
if (age < 0) {
    throw new IllegalArgumentException("Age cannot be negative");
}

